import { useState } from 'react';
import { ChevronDown, X, Shield, Brain, BarChart2, Globe, Award, Network } from 'lucide-react';
import SectionHeader from './SectionHeader';
import { useApp } from '../context/AppContext';
import t from '../i18n/translations';

// All certs with real images where available
const groupsData = [
  {
    key:'cyber', icon:<Shield size={16}/>, color:'teal',
    certs:[
      { org:'Google / Coursera', name:'Foundations of Cybersecurity', date:'Dec 2025', img:null },
      { org:'Google / Coursera', name:'Play It Safe: Manage Security Risks', date:'Feb 2026', img:null },
      { org:'Google / Coursera', name:'Connect & Protect: Networks & Network Security', date:'Mar 2026', img:null },
      { org:'Google / Coursera', name:'Tools of the Trade: Linux and SQL', date:'Mar 2026', img:null },
      { org:'Google / Coursera', name:'Assets, Threats, and Vulnerabilities', date:'Mar 2026', img:null },
      { org:'Sprints × Microsoft', name:'Cybersecurity Summer Camp (40 hrs)', date:'2024', img:null },
      { org:'HP LIFE', name:'Cybersecurity Awareness', img:null },
    ],
  },
  {
    key:'ai', icon:<Brain size={16}/>, color:'amber',
    certs:[
      { org:'NVIDIA Academy', name:'AI for All: From Basics to GenAI Practice', date:'Jan 2026', img:null },
      { org:'NVIDIA Academy', name:'Building LLM Applications with Prompt Engineering', date:'Feb 2026', img:null },
      { org:'IBM / Coursera', name:'Introduction to Artificial Intelligence', date:'Feb 2025', img:null },
      { org:'IBM / Coursera', name:'Delivering Quality Work with Agility', date:'Jan 2026', img:null },
      { org:'Dubai Future Foundation', name:'AI Prompt Engineering — 1 Million Prompters', img:'/assets/certs/dubai-ai.jpg' },
      { org:'HP LIFE', name:'Data Science & Analytics', img:null },
    ],
  },
  {
    key:'net', icon:<Network size={16}/>, color:'blue',
    certs:[
      { org:'Cisco Networking Academy', name:'Networking Basics', date:'Jul 2025', img:'/assets/certs/cisco-badge.jpg' },
    ],
  },
  {
    key:'digital', icon:<Globe size={16}/>, color:'coral',
    certs:[
      { org:'Google', name:'Digital Marketing Fundamentals', img:null },
      { org:'Banque Misr × Google', name:'Maharat min Google — Digital Marketing', img:'/assets/certs/google-maharat.jpg' },
      { org:'HP LIFE', name:'Digital Business Skills', img:null },
    ],
  },
  {
    key:'tech', icon:<BarChart2 size={16}/>, color:'lav',
    certs:[
      { org:'Meta / Coursera', name:'Introduction to Data Analytics', date:'Sep 2024', img:null },
      { org:'ITI Mahara-Tech', name:'Python Programming Basics', date:'Nov 2025', img:null },
      { org:'EYouth Learning', name:'Blockchain Technology', img:'/assets/certs/eyouth.jpg' },
      { org:'LinkedIn Learning', name:'Sustainability Foundations: Core Concepts', date:'Aug 2025', img:null },
    ],
  },
];

const groupLabels = {
  en: { cyber:'Cybersecurity (6/6 Google ✅)', ai:'AI & Gen AI', net:'Networking', digital:'Digital & Business', tech:'Tech & Other' },
  ar: { cyber:'الأمن السيبراني (6/6 Google ✅)', ai:'الذكاء الاصطناعي', net:'الشبكات', digital:'التسويق الرقمي', tech:'التقنية وغيرها' },
};

const colorMap = {
  teal:  { btn:'bg-teal/10 text-teal2 border-teal/20',  bar:'bg-teal' },
  amber: { btn:'bg-amber/10 text-amber2 border-amber/20', bar:'bg-amber' },
  blue:  { btn:'bg-blue-400/10 text-blue-500 border-blue-400/20', bar:'bg-blue-400' },
  coral: { btn:'bg-coral/10 text-coral border-coral/20',  bar:'bg-coral' },
  lav:   { btn:'bg-lav/20 text-purple-500 border-lav/30', bar:'bg-lav' },
};

function Modal({ src, name, onClose }) {
  if (!src) return null;
  return (
    <div className="fixed inset-0 z-50 bg-black/70 backdrop-blur-sm flex items-center justify-center p-4" onClick={onClose}>
      <div className="relative max-w-2xl w-full" onClick={e => e.stopPropagation()}>
        <button onClick={onClose} className="absolute -top-10 right-0 text-white/70 hover:text-white"><X size={24}/></button>
        <img src={src} alt={name} className="w-full rounded-2xl shadow-2xl" />
        <p className="text-center text-white/60 text-sm mt-3">{name}</p>
      </div>
    </div>
  );
}

export default function Certs() {
  const { dark, lang } = useApp();
  const tr = t[lang];
  const [open, setOpen] = useState(0); // Default open first group
  const [modal, setModal] = useState(null);
  const labels = groupLabels[lang];

  const bg = dark ? 'bg-[#13131e]' : 'bg-parchment';
  const cardBg = dark ? 'bg-[#1a1a28]' : 'bg-cream';
  const achBg = dark ? 'bg-[#0f0f14]' : 'bg-cream';
  const achCard = dark ? 'bg-[#13131e]' : 'bg-parchment';

  return (
    <>
      <section id="certs" className={`py-24 px-[5%] ${bg} transition-colors duration-300`}>
        <SectionHeader tag={tr.certsTag} title={tr.certsTitle} />
        <p className={`text-sm mb-8 -mt-6 ${dark?'text-white/35':'text-muted'}`}>{tr.certsHint}</p>

        <div className="flex flex-col gap-3 max-w-3xl">
          {groupsData.map((g, gi) => {
            const cm = colorMap[g.color];
            return (
              <div key={gi} className="reveal">
                <button onClick={() => setOpen(open===gi?null:gi)}
                  className={`w-full flex items-center justify-between px-5 py-4 rounded-2xl border transition-all hover:shadow-md ${cm.btn}`}>
                  <div className="flex items-center gap-3">
                    <span>{g.icon}</span>
                    <span className="font-semibold text-sm">{labels[g.key]}</span>
                    <span className="text-xs opacity-60">({g.certs.length})</span>
                  </div>
                  <ChevronDown size={16} className={`transition-transform duration-300 ${open===gi?'rotate-180':''}`}/>
                </button>

                {open === gi && (
                  <div className="mt-2 grid sm:grid-cols-2 gap-2 pl-2">
                    {g.certs.map((c, ci) => (
                      <div key={ci}
                        onClick={() => c.img && setModal(c)}
                        className={`relative ${cardBg} rounded-xl px-4 py-3.5 border-[1.5px] border-transparent overflow-hidden transition-all hover:border-amber/20 hover:-translate-y-0.5 hover:shadow-md ${c.img?'cursor-pointer':'cursor-default'} group`}
                        style={{ animation:`fadeUp .3s ${ci*0.05}s ease both` }}>
                        <div className={`absolute top-0 left-0 right-0 h-[2px] ${cm.bar} opacity-60 scale-x-0 group-hover:scale-x-100 transition-transform origin-left`} />
                        <div className="flex items-start justify-between gap-2">
                          <div className="min-w-0">
                            <p className="text-[.6rem] font-semibold tracking-wider uppercase text-amber mb-1">{c.org}</p>
                            <p className={`text-[.84rem] font-semibold leading-snug ${dark?'text-white/80':'text-ink2'}`}>{c.name}</p>
                            {c.date && <p className={`text-[.65rem] mt-0.5 ${dark?'text-white/35':'text-muted'}`}>{c.date}</p>}
                          </div>
                          {c.img && <Award size={13} className="text-muted opacity-50 group-hover:opacity-100 group-hover:text-amber transition-all flex-shrink-0 mt-1"/>}
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </section>

      {/* Achievements */}
      <section id="achievements" className={`py-24 px-[5%] ${achBg} transition-colors duration-300`}>
        <SectionHeader tag={tr.achTag} title={tr.achTitle} />
        <div className="grid md:grid-cols-2 gap-4 max-w-3xl">
          {tr.achievements.map((a, i) => (
            <div key={i}
              className={`reveal ${i===1?'delay-1':''} flex gap-4 items-start ${achCard} rounded-2xl p-6 border-[1.5px] border-transparent shadow-sm transition-all hover:border-amber/22 hover:-translate-y-1 hover:shadow-lg cursor-default`}>
              <div className="text-3xl bg-amber/8 p-3 rounded-xl flex-shrink-0 leading-none">{a.icon}</div>
              <div>
                <p className="text-[.65rem] font-semibold tracking-wider uppercase text-amber mb-1">{a.year}</p>
                <h3 className={`font-serif-display text-lg tracking-tight mb-2 ${dark?'text-white':'text-ink'}`}>{a.title}</h3>
                <p className={`text-[.85rem] leading-[1.7] ${dark?'text-white/55':'text-muted2'}`}>{a.desc}</p>
              </div>
            </div>
          ))}
        </div>
      </section>

      {modal && <Modal src={modal.img} name={modal.name} onClose={() => setModal(null)} />}
    </>
  );
}
